SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND ((t.Volume_3M_P50*t.Price/ NULLIF(t.Inflation_7, 0))>3400000000.0) AND (t.Risk_Rating <= 6) AND (t.PE/((t.NP_P0/ NULLIF(t.NP_P4, 0) -1)*100) < 0.64) AND (t.ROE_Min5Y > 0.07) AND ((t.FSCORE>=4)) AND (t.NP_P0/ NULLIF(t.NP_P4, 0) > 1.04) AND (t.NP_P4 >= 0) AND (t.PCF > 0.1) AND (t.PCF < 11.0) AND (t.CF_OA_5Y/ NULLIF(t.OShares, 0) > 3000.0) AND (t.ID_Current -  t.ID_Release <= 14.0) ORDER BY t.ticker, t.time